var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"한참을 내려왔는데, 아직도 더 내려간다고?","JPN":"まだ降りるのか？","ENG":"How far does this lift go down? It feels like forever.","TWN":"咳，都下來半天了，還要往下走？"},"stage":{"bg":"LIFT","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"대체 몇 층을 내려가고 있는 거야?","JPN":"いったいどこまで降りるんだ？","ENG":"How many floors are left?","TWN":"到底要下多少層？"},"stage":{"bg":"LIFT","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"혼란스럽겠지만 이제 몇 층을 내려왔는지 같은 건 중요하지 않네.","JPN":"混乱しているだろうが、そんなことはもう重要ではない。","ENG":"It might be confusing to you, but it doesn't matter how far we're going down.","TWN":"雖然很混亂，但是下到幾樓並不重要。"},"stage":{"bg":"LIFT","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"워치를 확인해보게. 이곳은 현실세계가 아니거든.","JPN":"ウォッチを確認してみろ。ここは現実世界ではないのだ。","ENG":"Look at your Watch. This place isn't the Normalside.","TWN":"確認一下能量環吧，這裡可不是現世。"},"stage":{"bg":"LIFT","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐야, 정말로 이면세계잖아?","JPN":"なんだ、本当に裏世界じゃないか。","ENG":"Huh? We're really in the Counterside?","TWN":"什麼啊，竟然是異界。"},"stage":{"bg":"LIFT","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그래. <color=#ffd34c>맥크레디 포인트</color>에 대해서는 가르쳐 준 적 있지?","JPN":"ああ。<color=#ffd34c>マクレディーポイント</color>については教えたことがあるはずだ。","ENG":"Correct. I've told you about <color=#ffd34c>MacCready Point</color> before, right?","TWN":"沒錯。關於<color=#ffd34c>麥克蕾蒂領地</color>，有教過你吧？"},"stage":{"bg":"LIFT","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"알고 있어. 학회장이 살고 있는 동네 아니야. 버뮤다 삼각지대 같은 거라면서?","JPN":"わかってる。学会長が住んでる街だろ？　バミューダトライアングルみたいなものだっけ？","ENG":"I know about that. It's where the President lives. Didn't you say that place was like the Bermuda Triangle?","TWN":"我知道，是學會長住的地方吧。聽說是類似於百慕達三角洲的地方？"},"stage":{"bg":"LIFT","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"좋아. 잘 기억하고 있구만.","JPN":"よし。ちゃんと覚えているな。","ENG":"Good. So you do remember.","TWN":"沒錯，你記得很清楚呢。"},"stage":{"bg":"LIFT","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"이곳 역시 여러 아티팩트를 공명시켜 만들어낸 특수한 공간이라고 생각하면 돼.","JPN":"ここもまた色々なアーティファクトを共鳴させて作り出した特殊な空間と思えばいい。","ENG":"Think of here as a special space created through resonating various Artifacts.","TWN":"你把這裡當成是多個人造神器共鳴而形成的特殊空間就好。"},"stage":{"bg":"LIFT","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"일반적인 방법으로는 절대 접근이 불가능하지.","JPN":"一般的な方法では決して近づくことができないのだ。","ENG":"It's impossible to reach here using conventional methods.","TWN":"用一般的方法是絕對不可能接近的。"},"stage":{"bg":"LIFT","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐 때문에 그런 짓을 하는 건데?","JPN":"なんのためにそんなことを？","ENG":"Why would someone go through all this hassle then?","TWN":"為什麼要那麼做？"},"stage":{"bg":"LIFT","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"일종의 보험이랍니다, 물벼룩.","JPN":"ある種の保険ですわ、ミジンコ。","ENG":"It's a kind of insurance, Water Flea.","TWN":"這是一種保險，水蚤。"},"stage":{"bg":"LIFT","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"지금 우리가 향하는 곳은 최고 레벨의 아티팩트 보관실. 일명, <color=#ffd34c>성궤</color>라고 불리는 곳이죠.","JPN":"今私たちが向かっている場所は、最高レベルのアーティファクト保管室。別名、<color=#ffd34c>聖櫃</color>と呼ばれるところです。","ENG":"Where we are headed right now is the Artifact storage room of the highest level. Also known as the <color=#ffd34c>Ark of the Covenant</color>.","TWN":"我們現在要去的是最高級別人造神器的保管室，又名<color=#ffd34c>聖軌</color>。"},"stage":{"bg":"LIFT","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그곳의 아티팩트는 절대로 적에게 넘어가서는 안 되는 물건들이에요.","JPN":"あそこのアーティファクトは決して敵に渡してはいけません。","ENG":"The Artifacts here must never be placed in the hands of our enemies.","TWN":"那裡的人造神器是絕對不能落入敵人手中的東西。"},"stage":{"bg":"LIFT","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"기관은 본부가 점령당하면, 유일한 출입구인 차원 엘리베이터를 폭파시켜 성궤를 현실로부터 격리합니다.","JPN":"機関は本部が占領されると、唯一の出入口である次元エレベーターを爆破し、聖櫃を現実から隔離します。","ENG":"If the Institution's headquarters were to be taken over, the dimensional lift, which serves as the only entrance, would be obliterated, isolating the Ark of the Covenant from the Normalside.","TWN":"如果總部被佔領，機關就會炸毀唯一的出入口次元電梯，將聖軌與現世隔離。"},"stage":{"bg":"LIFT","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"아티팩트가 학회 손에 들어갈 바에는 아예 없애 버리는 편이 더 낫다는 뜻이야?","JPN":"アーティファクトが学会の手に渡るくらいなら、いっそ消した方がいいってことなのか？","ENG":"So it's better to get rid of the Artifacts than to have them in the hands of the Society?","TWN":"與其讓人造神器落入學會手中，還不如乾脆除掉對嗎？"},"stage":{"bg":"LIFT","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFT","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"도착했군요. 성궤에 온 걸 환영합니다, 물벼룩.","JPN":"着きましたわ。聖櫃へようこそ、ミジンコ。","ENG":"We've arrived. Welcome to the Ark of the Covenant, Water Flea.","TWN":"到了，歡迎來到聖軌，水蚤。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"우리가 찾는 아티팩트는 이쪽이에요.","JPN":"私たちの探しているアーティファクトはこちらです。","ENG":"The Artifact we are looking for is over there.","TWN":"我們要找的人造神器在這邊。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐야, 이 <color=#ffd34c>방패</color>는?","JPN":"なんだ、この<color=#ffd34c>盾</color>は？","ENG":"Huh? What's this <color=#ffd34c>shield</color>?","TWN":"這個<color=#ffd34c>盾牌</color>是什麼？"},"stage":{"bg":"PRYDWEN_05","slots":{"L":null,"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"잠깐, 방패를 감싸고 있는 사슬들은 설마……?","JPN":"待てよ、この盾に巻き付いている鎖は、まさか……？","ENG":"Wait a minute. Those chains wrapped around the shield... Are they...?","TWN":"等等，圍繞著盾牌的鐵鍊難道是……？"},"stage":{"bg":"PRYDWEN_05","slots":{"L":null,"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"당신이 가진 <color=#ffd34c>봉인 사슬</color>과 같은 것이죠.","JPN":"そう、あなたが持っている<color=#ffd34c>封印の鎖</color>と同じものです。","ENG":"They are the same as your <color=#ffd34c>Sealing Chain</color>.","TWN":"和你擁有的<color=#ffd34c>封印鎖鏈</color>是一樣的。"},"stage":{"bg":"PRYDWEN_05","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"애초에 비밀 격리 시설에서 파편을 봉인하고 있는 사슬은 전부 이 방패에서 생성된 부산물에 불과하답니다.","JPN":"そもそも秘密隔離施設で破片を封印している鎖は、すべてこの盾から生成された副産物に過ぎません。","ENG":"First and foremost, the chains that seal the Fragments in the secret quarantine facilities are byproducts of this shield.","TWN":"最初在秘密隔離設施中，封印碎片的鐵鍊都是從這個盾牌生成的附屬品。"},"stage":{"bg":"PRYDWEN_05","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"봉인 사슬이…… 방패의 부산물이라고?","JPN":"封印の鎖が……盾の副産物だと？","ENG":"The Sealing Chain is... a byproduct of this shield?","TWN":"封印鎖鏈……是盾牌的附屬品？"},"stage":{"bg":"PRYDWEN_05","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};